/// </summary>
/// <remarks>
/// This type is designed to be used from code generated by Rocks,
/// and is not intended for general use. Please refrain from
/// referencing it for any other purposes, as its implementation may change.
/// </remarks>
[Serializable]
public sealed class NewMockInstanceException
	: Exception
{
	/// <summary>
	/// Creates a new <see cref="NewMockInstanceException"/> instance
	/// with the specified message.
	/// </summary>
	/// <param name="message">The message.</param>
	public NewMockInstanceException(string message)
		: base(message) { }
}